public static class ResourceRenewalCatalogV3
{
    private static readonly IReadOnlyDictionary<(BiomeKindV3,string),ResourceRenewalRuleV3> Rules=Build(false);
    public static bool TryGet(BiomeKindV3 biome,string definition,out ResourceRenewalRuleV3? rule)=>Rules.TryGetValue((biome,definition),out rule);
    public static IReadOnlyDictionary<(BiomeKindV3,string),ResourceRenewalRuleV3> CreateAcceleratedTestRules()=>Build(true);
    private static IReadOnlyDictionary<(BiomeKindV3,string),ResourceRenewalRuleV3> Build(bool test)
    {
        double s=test?.01:1;var d=new Dictionary<(BiomeKindV3,string),ResourceRenewalRuleV3>();
        Add(BiomeKindV3.ForestLand,NaturalResourceDefinitionCatalogV3.TreeId,600,90,.85,1,6,.9,.18,4,6,10);
        Add(BiomeKindV3.Plains,NaturalResourceDefinitionCatalogV3.TreeId,1800,180,.55,.70,5,.55,.06,5,3,8);
        Add(BiomeKindV3.RockyHills,NaturalResourceDefinitionCatalogV3.TreeId,7200,360,.05,.10,4,.15,.002,8,1,2);
        AddStone(BiomeKindV3.RockyHills,1800,240,.80,.95,4,10);AddStone(BiomeKindV3.Plains,5400,360,.35,.50,2,6);AddStone(BiomeKindV3.ForestLand,7200,480,.20,.35,1,4);
        foreach(BiomeKindV3 biome in Enum.GetValues<BiomeKindV3>())
        {if(!d.ContainsKey((biome,NaturalResourceDefinitionCatalogV3.TreeId)))d[(biome,NaturalResourceDefinitionCatalogV3.TreeId)]=d[(BiomeKindV3.Plains,NaturalResourceDefinitionCatalogV3.TreeId)] with{RuleId=$"renew.{biome}.tree"};if(!d.ContainsKey((biome,NaturalResourceDefinitionCatalogV3.StoneId)))d[(biome,NaturalResourceDefinitionCatalogV3.StoneId)]=d[(BiomeKindV3.Plains,NaturalResourceDefinitionCatalogV3.StoneId)] with{RuleId=$"renew.{biome}.stone"};}
        return new ReadOnlyDictionary<(BiomeKindV3,string),ResourceRenewalRuleV3>(d);
        void Add(BiomeKindV3 b,string id,double cd,double retry,double target,double max,int radius,double parent,double seed,double extraCooldown,double credits,int priority)=>d[(b,id)]=new($"renew.{b}.tree",id,NaturalResourceRenewalClassV3.VegetativeSpread,cd*s,retry*s,target,max,radius,parent,ResourceRenewalParentModeV3.Preferred,seed,test?2:extraCooldown,1,1,credits,1,priority);
        void AddStone(BiomeKindV3 b,double cd,double retry,double target,double max,double credits,int priority)=>d[(b,NaturalResourceDefinitionCatalogV3.StoneId)]=new($"renew.{b}.stone",NaturalResourceDefinitionCatalogV3.StoneId,NaturalResourceRenewalClassV3.GeologicalExposure,cd*s,retry*s,target,max,0,0,ResourceRenewalParentModeV3.None,0,1,1,1,credits,1,priority);
    }
    public static bool TryValidate(out string reason){var ids=new HashSet<string>(StringComparer.Ordinal);foreach(var r in Rules.Values){if(!ids.Add(r.RuleId)||!NaturalResourceDefinitionCatalogV3.TryGet(r.ResourceDefinitionId,out _)||r.BaseCooldownSeconds<=0||r.RetryBackoffSeconds<=0||!double.IsFinite(r.TargetDensityRatio)||r.TargetDensityRatio<0||r.MaximumDensityRatio<r.TargetDensityRatio||r.ParentInfluenceRadius<0||r.ParentInfluenceRadius>16||r.MaximumStoredCredits<0||r.MaximumStoredCredits>64){reason="InvalidRenewalRule";return false;}}reason=string.Empty;return true;}
}

