public interface IResourceEcologyWorldQueryV3
{
    bool TryGetActiveChunk(Vector2I chunk,out ChunkDataV2? data);
    bool IsPersistentExcluded(Vector2I cell,out string reason);
    bool IsTransientExcluded(Vector2I cell,out string reason);
    ResourceRenewalExclusionResultV3 EvaluateExclusion(ResourceRenewalExclusionContextV3 context)
    {
        if(IsPersistentExcluded(context.GlobalCell,out string persistent))
            return new(false,ResourceRenewalExclusionKindV3.Structure,false,60,persistent,0);
        if(IsTransientExcluded(context.GlobalCell,out string transient))
            return new(false,ResourceRenewalExclusionKindV3.Mercenary,true,5,transient,0);
        return ResourceRenewalExclusionResultV3.Allowed();
    }
    int GetOccupancyRevision(Vector2I cell)=>0;
}

