    private void OnRegistered(ResourceNodeStateV3 node){if(node.IsDepleted||!TryRenewableDefinition(node.NodeType,out string definition)||!_knownAlive.Add(node.ResourceNodeId))return;var key=new ResourceEcologyKeyV3(WorldV2CoordinateUtility.GlobalCellToGlobalChunkCoord(node.Cell.Value),definition);if(_states.TryGetValue(key,out var state))state.CurrentNodeCount++;if(node.OriginKind is NaturalResourceOriginKindV3.VegetativeSpread or NaturalResourceOriginKindV3.SeedBankRecovery or NaturalResourceOriginKindV3.GeologicalExposure&&TryGetPressure(key,out var pressure)&&pressure?.HighestTier!=ResourceShortageTierV3.None)RecordSafetySpawn(key);}
